//! Provides a unified interface for all human-facing output, automatically
//! routing to stderr and detecting terminal capabilities.
//!
//! ## Why This Wrapper Exists
//!
//! 1. **stderr by default**: Agents parse stdout JSON, humans see stderr
//! 2. **TTY detection integration**: Uses existing should_use_rich_output()
//! 3. **Global singleton**: Consistent formatting across all modules
//! 4. **Environment control**: Respects NO_COLOR, CI, DCG_NO_RICH

#[cfg(feature = "rich-output")]
use rich_rust::prelude::*;

use std::sync::OnceLock;

/// Global console instance.
static CONSOLE: OnceLock<DcgConsole> = OnceLock::new();

/// dcg-specific console wrapper.
pub struct DcgConsole {
    #[cfg(feature = "rich-output")]
    inner: Console,
    force_plain: bool,
}

impl DcgConsole {
    /// Create a new console that writes to stderr.
    #[cfg(feature = "rich-output")]
    pub fn new() -> Self {
        let inner = Console::new()
            .with_stderr()  // CRITICAL: all output to stderr
            .with_force_terminal(false);

        Self {
            inner,
            force_plain: false,
        }
    }

    /// Create a plain-text console (no colors, no unicode).
    pub fn plain() -> Self {
        #[cfg(feature = "rich-output")]
        let inner = Console::new().with_stderr().with_no_color();

        Self {
            #[cfg(feature = "rich-output")]
            inner,
            force_plain: true,
        }
    }

    /// Print styled text using markup syntax.
    #[cfg(feature = "rich-output")]
    pub fn print(&self, text: &str) {
        if self.force_plain {
            self.inner.print_plain(text);
        } else {
            self.inner.print(text);
        }
    }

    /// Print a renderable (Panel, Table, etc.).
    #[cfg(feature = "rich-output")]
    pub fn print_renderable<R>(&self, renderable: &R)
    where
        R: rich_rust::Renderable,
    {
        self.inner.print_renderable(renderable);
    }

    /// Print a horizontal rule.
    #[cfg(feature = "rich-output")]
    pub fn rule(&self, title: Option<&str>) {
        self.inner.rule(title);
    }

    /// Get terminal width.
    pub fn width(&self) -> usize {
        #[cfg(feature = "rich-output")]
        return self.inner.width();

        #[cfg(not(feature = "rich-output"))]
        return crate::output::terminal_width() as usize;
    }
}

/// Get the global console instance.
pub fn console() -> &'static DcgConsole {
    CONSOLE.get_or_init(|| {
        // Check environment variables
        if std::env::var("DCG_NO_RICH").is_ok() {
            return DcgConsole::plain();
        }

        if crate::output::should_use_rich_output() {
            DcgConsole::new()
        } else {
            DcgConsole::plain()
        }
    })
}

/// Initialize console with explicit settings (call early in main).
pub fn init_console(force_plain: bool) {
    let _ = CONSOLE.set(if force_plain {
        DcgConsole::plain()
    } else {
        DcgConsole::new()
    });
}
```

### Key Design Decisions

1. **OnceLock singleton**: Thread-safe, initialized on first use
2. **Conditional compilation**: Compiles without rich_rust feature
3. **Environment variable precedence**: DCG_NO_RICH overrides all
4. **Fallback to plain**: Graceful degradation when rich output unavailable

### Tests to Add

```rust
#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn console_returns_valid_width() {
        let console = DcgConsole::plain();
        assert!(console.width() > 0);
    }

    #[test]
    fn dcg_no_rich_forces_plain() {
        std::env::set_var("DCG_NO_RICH", "1");
        // Reinitialize would use plain
        std::env::remove_var("DCG_NO_RICH");
    }
}
```
